  private static Dictionary<string, string> S(
    string en, string ru, string uk, string es, string de,
    string fr, string it, string pt, string pl, string ja)
  {
    var texts = new[] { en, ru, uk, es, de, fr, it, pt, pl, ja };
    if (texts.Length != LangOrder.Length)
      throw new InvalidOperationException($"Translation count mismatch: expected {LangOrder.Length}, got {texts.Length}.");

    var map = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
    for (var i = 0; i < LangOrder.Length; i++)
      map[LangOrder[i]] = texts[i];
    return map;
  }

  public static string Get(string language, string key)
  {
    if (!Data.TryGetValue(key, out var langs))
      return key;

    if (langs.TryGetValue(language, out var text))
      return text;

    return langs.TryGetValue("en", out var en) ? en : key;
  }

  public static string QualityLabel(string language, string qualityName) =>
    qualityName.ToLowerInvariant() switch
    {
      "low" => Get(language, "quality.low"),
      "normal" => Get(language, "quality.normal"),
      "high" => Get(language, "quality.high"),
      _ => qualityName
    };

  public static string SearchTabLabel(string language, SearchTab tab) =>
    tab switch
    {
      SearchTab.All => Get(language, "search.tab.all"),
      SearchTab.Tracks => Get(language, "search.tab.tracks"),
      SearchTab.Albums => Get(language, "search.tab.albums"),
      SearchTab.Artists => Get(language, "search.tab.artists"),
      SearchTab.Podcasts => Get(language, "search.tab.podcasts"),
      _ => tab.ToString()
    };
}
